$ErrorActionPreference = "Stop"

$project = "C:\Users\arauj\grafica-flash"

if (!(Test-Path $project)) {
  Write-Host "Projeto nao encontrado em $project" -ForegroundColor Red
  exit 1
}

Set-Location $project

$utf8NoBom = New-Object System.Text.UTF8Encoding($false)

function Write-Base64File($relativePath, $base64Content) {
  $target = Join-Path $project $relativePath
  $directory = Split-Path $target -Parent

  New-Item -ItemType Directory -Force $directory | Out-Null

  $bytes = [System.Convert]::FromBase64String($base64Content.Trim())
  $content = [System.Text.Encoding]::UTF8.GetString($bytes)

  [System.IO.File]::WriteAllText($target, $content, $utf8NoBom)
}


Write-Base64File "proxy.ts" @"

"@

Write-Base64File "lib\domain.ts" @"

"@

# Next 16 recomenda proxy.ts. Se existir middleware.ts, faz backup e remove para acabar com o aviso.
if (Test-Path "middleware.ts") {
  Copy-Item "middleware.ts" "middleware.backup-before-proxy.ts" -Force
  Remove-Item "middleware.ts" -Force
  Write-Host "middleware.ts removido e salvo como middleware.backup-before-proxy.ts" -ForegroundColor Yellow
}

# Ajusta app/orcamento/[slug]/page.tsx para aceitar slug OU subdomain_slug.
$loja = Join-Path $project "app\orcamento\[slug]\page.tsx"

if (Test-Path $loja) {
  $content = [System.IO.File]::ReadAllText($loja)

  # Inclui subdomain_slug no select se ainda não estiver.
  if ($content -notmatch "subdomain_slug") {
    $content = $content.Replace(
      "id, nome, slug, logo_url",
      "id, nome, slug, subdomain_slug, logo_url"
    )
  }

  # Troca busca exata por slug para aceitar subdomain_slug também.
  $content = $content.Replace(
    ".eq('slug', slug)",
    ".or(`slug.eq.${slug},subdomain_slug.eq.${slug}`)"
  )

  [System.IO.File]::WriteAllText($loja, $content, $utf8NoBom)
  Write-Host "Loja publica ajustada para slug e subdomain_slug." -ForegroundColor Green
} else {
  Write-Host "Nao encontrei app\orcamento\[slug]\page.tsx" -ForegroundColor Yellow
}

# Se cadastro tiver insert de companies, adiciona subdomain_slug visualmente. O trigger do banco ja cobre isso,
# mas assim o front tambem manda o valor limpo.
$cadastro = Join-Path $project "app\cadastro\page.tsx"

if (Test-Path $cadastro) {
  $content = [System.IO.File]::ReadAllText($cadastro)

  if ($content -notmatch "@/lib/domain") {
    $content = $content -replace "(?m)^import .* from '@/lib/security'.*$", '$0' + "`nimport { criarSubdominioSeguro } from '@/lib/domain'"
  }

  if ($content -notmatch "subdomain_slug") {
    $content = $content.Replace(
      "slug: slugValidado.slug,",
      "slug: slugValidado.slug,`n          subdomain_slug: criarSubdominioSeguro(nomeEmpresa),"
    )
  }

  [System.IO.File]::WriteAllText($cadastro, $content, $utf8NoBom)
  Write-Host "Cadastro ajustado para salvar subdomain_slug." -ForegroundColor Green
}

# Garante .env.example com domínio raiz sem expor segredo.
$envExample = Join-Path $project ".env.example"
if (!(Test-Path $envExample)) {
  [System.IO.File]::WriteAllText($envExample, "", $utf8NoBom)
}

$envContent = [System.IO.File]::ReadAllText($envExample)

if ($envContent -notmatch "NEXT_PUBLIC_ROOT_DOMAIN") {
  Add-Content -Path $envExample -Value "NEXT_PUBLIC_ROOT_DOMAIN=orcaly.com.br"
}

Remove-Item -Recurse -Force ".next" -ErrorAction SilentlyContinue

Write-Host ""
Write-Host "Subdominio por empresa instalado." -ForegroundColor Green
Write-Host "Exemplo: graficaflash.orcaly.com.br" -ForegroundColor Cyan
Write-Host "Agora rode: npm run build" -ForegroundColor Yellow
